import java.io.*;

public class CommandInjectionFixed {
    public static void main(String[] args) {
        try {
            BufferedReader reader = new BufferedReader(new InputStreamReader(System.in));
            System.out.print("Enter a command to execute: ");
            String input = reader.readLine().trim();

            // Validate user input for allowed commands
            if (!input.matches("[a-zA-Z0-9.-_]+")) {
                System.out.println("Invalid command. Only alphanumeric characters, dot, dash, and underscore are allowed.");
                return;
            }

            String[] command = { "/bin/sh", "-c", input }; // Execute the command securely

            Process process = Runtime.getRuntime().exec(command);

            BufferedReader inputStreamReader = new BufferedReader(new InputStreamReader(process.getInputStream()));
            String line;
            while ((line = inputStreamReader.readLine()) != null) {
                System.out.println(line);
            }
        } catch (IOException e) {
            e.printStackTrace();
        }
    }
}

